  6	import { useNMStateTranslation } from 'src/utils/hooks/useNMStateTranslation';
  7	import { useImmer } from 'use-immer';
  8	
  9	import { IoK8sApiCoreV1Node } from '@kubevirt-ui/kubevirt-api/kubernetes/models';
 10	import { useK8sWatchResource } from '@openshift-console/dynamic-plugin-sdk';
 11	import {
 12	  ActionGroup,
 13	  Alert,
 14	  AlertVariant,
 15	  Button,
 16	  ButtonType,
 17	  ButtonVariant,
 18	  Form,
 19	  Modal,
 20	  ModalVariant,
 21	} from '@patternfly/react-core';
 22	import { V1beta1NodeNetworkConfigurationEnactment, V1NodeNetworkConfigurationPolicy } from '@types';
 23	
 24	import LabelsList from './components/LabelList';
 25	import LabelRow from './components/LabelRow';
 26	import NodeCheckerAlert from './components/NodeCheckerAlert';
 27	import { IDLabel } from './utils/types';
 28	
 29	type NodeSelectorModalProps = {
 30	  policy: V1NodeNetworkConfigurationPolicy;
 31	  isOpen: boolean;
 32	  onClose: () => void;
 33	  onSubmit: (
 34	    newNNCP: V1NodeNetworkConfigurationPolicy,
 35	  ) => Promise<V1NodeNetworkConfigurationPolicy | void> | void;
 36	};
 37	const NodeSelectorModal: FC<NodeSelectorModalProps> = ({ policy, isOpen, onClose, onSubmit }) => {
 38	  const { t } = useNMStateTranslation();
 39	  const [nodes, nodesLoaded] = useK8sWatchResource<IoK8sApiCoreV1Node[]>({
 40	    groupVersionKind: NodeModelGroupVersionKind,
 41	    isList: true,
 42	  });
 43	
 44	  const [enactments, enactmentsLoaded] = useK8sWatchResource<
 45	    V1beta1NodeNetworkConfigurationEnactment[]
 46	  >({
 47	    groupVersionKind: NodeNetworkConfigurationEnactmentModelGroupVersionKind,
 48	    isList: true,
 49	  });
 50	
 51	  const [selectorLabels, setSelectorLabels] = useImmer(
 52	    Object.entries(policy.spec?.nodeSelector || {}).map(([key, value], index) => ({
 53	      key,
 54	      value,
 55	      id: index,
 56	    })),
 57	  );
 58	
 59	  const qualifiedNodes = nodes.filter((node) =>
 60	    selectorLabels.every((label) => node?.metadata?.labels[label.key] === label.value),
 61	  );
 62	
 63	  const onSelectorLabelAdd = () => {
 64	    setSelectorLabels((selectors) => [...selectors, { key: '', value: '', id: selectors.length }]);
 65	  };
 66	
 67	  const onLabelChange = (label: IDLabel) => {
 68	    const index = selectorLabels.findIndex((s) => s.id === label.id);
 69	
 70	    if (index !== -1) {
 71	      setSelectorLabels((draftSelectorLabels) => {
 72	        draftSelectorLabels[index].key = label.key;
 73	        draftSelectorLabels[index].value = label.value;
 74	      });
 75	    }
 76	  };
 77	  const onLabelDelete = (id: number) => {
 78	    setSelectorLabels((selectors) => selectors.filter((s) => s.id !== id));
 79	  };
 80	
 81	  const onSave: MouseEventHandler<HTMLButtonElement> = (event) => {
 82	    event.preventDefault();
 83	    const nodeSelector = selectorLabels.reduce((acc, selector) => {
 84	      acc[selector.key] = selector.value;
 85	      return acc;
 86	    }, {});
 87	
 88	    const newPolicy = produce(policy, (draftPolicy) => {
 89	      selectorLabels.length === 0
 90	        ? delete draftPolicy.spec.nodeSelector
 91	        : (draftPolicy.spec.nodeSelector = nodeSelector);
 92	    });
 93	
 94	    return onSubmit(newPolicy);
 95	  };
 96	
 97	  const nodeAlreadyCovered = qualifiedNodes.find((node) =>
 98	    enactments.find(
 99	      (enactment) => enactment?.metadata?.labels?.[ENACTMENT_LABEL_NODE] === node.metadata.name,
100	    ),
101	  );
102	
103	  return (
104	    <Modal
105	      onClose={onClose}
106	      isOpen={isOpen}
107	      variant={ModalVariant.small}
108	      className="ocs-modal"
109	      title={t('Node Selector')}
110	    >
111	      <Form>
112	        <LabelsList model={nodes?.length !== 0 && NodeModel} onLabelAdd={onSelectorLabelAdd}>
113	          {selectorLabels.length > 0 && (
114	            <>
115	              {selectorLabels.map((label) => (
116	                <LabelRow
117	                  key={label.id}
118	                  label={label}
119	                  onChange={onLabelChange}
120	                  onDelete={onLabelDelete}
121	                />
122	              ))}
123	            </>
124	          )}
125	        </LabelsList>
126	        {nodes.length !== 0 && (
127	          <NodeCheckerAlert
128	            qualifiedNodes={selectorLabels?.length === 0 ? nodes : qualifiedNodes}
129	            nodesLoaded={nodesLoaded && enactmentsLoaded}
130	          />
131	        )}
132	
133	        {nodeAlreadyCovered && (
134	          <Alert
135	            variant={AlertVariant.warning}
136	            isInline
137	            title={t('This node already has a policy matching it')}
138	          >
139	            {t('Remove all dependencies between the new and existing polices')}
140	          </Alert>
141	        )}
142	
143	        <ActionGroup className="pf-v6-c-form">
144	          <Button type={ButtonType.submit} variant={ButtonVariant.primary} onClick={onSave}>
145	            {t('Save')}
146	          </Button>
147	          <Button type={ButtonType.button} variant={ButtonVariant.secondary} onClick={onClose}>
148	            {t('Cancel')}
149	          </Button>
150	        </ActionGroup>
151	      </Form>
152	    </Modal>
153	  );
154	};
155	
156	export default NodeSelectorModal;

