 26	import LabelsList from './components/LabelList';
 27	import LabelRow from './components/LabelRow';
 28	import NodeCheckerAlert from './components/NodeCheckerAlert';
 29	import { IDLabel } from './utils/types';
 30	
 31	type NodeSelectorModalProps = {
 32	  policy: V1NodeNetworkConfigurationPolicy;
 33	  isOpen: boolean;
 34	  onClose: () => void;
 35	  onSubmit: (
 36	    newNNCP: V1NodeNetworkConfigurationPolicy,
 37	  ) => Promise<V1NodeNetworkConfigurationPolicy | void> | void;
 38	};
 39	const NodeSelectorModal: FC<NodeSelectorModalProps> = ({ policy, isOpen, onClose, onSubmit }) => {
 40	  const { t } = useNMStateTranslation();
 41	  const [nodes, nodesLoaded] = useK8sWatchResource<IoK8sApiCoreV1Node[]>({
 42	    groupVersionKind: NodeModelGroupVersionKind,
 43	    isList: true,
 44	  });
 45	
 46	  const [enactments, enactmentsLoaded] = useK8sWatchResource<
 47	    V1beta1NodeNetworkConfigurationEnactment[]
 48	  >({
 49	    groupVersionKind: NodeNetworkConfigurationEnactmentModelGroupVersionKind,
 50	    isList: true,
 51	  });
 52	
 53	  const [selectorLabels, setSelectorLabels] = useImmer(
 54	    Object.entries(policy.spec?.nodeSelector || {}).map(([key, value], index) => ({
 55	      key,
 56	      value,
 57	      id: index,
 58	    })),
 59	  );
 60	
 61	  const qualifiedNodes = nodes.filter((node) =>
 62	    selectorLabels.every((label) => node?.metadata?.labels[label.key] === label.value),
 63	  );
 64	
 65	  const onSelectorLabelAdd = () => {
 66	    setSelectorLabels((selectors) => [...selectors, { key: '', value: '', id: selectors.length }]);
 67	  };
 68	
 69	  const onLabelChange = (label: IDLabel) => {
 70	    const index = selectorLabels.findIndex((s) => s.id === label.id);
 71	
 72	    if (index !== -1) {
 73	      setSelectorLabels((draftSelectorLabels) => {
 74	        draftSelectorLabels[index].key = label.key;
 75	        draftSelectorLabels[index].value = label.value;
 76	      });
 77	    }
 78	  };
 79	  const onLabelDelete = (id: number) => {
 80	    setSelectorLabels((selectors) => selectors.filter((s) => s.id !== id));
 81	  };
 82	
 83	  const onSave: MouseEventHandler<HTMLButtonElement> = (event) => {
 84	    event.preventDefault();
 85	    const nodeSelector = selectorLabels.reduce((acc, selector) => {
 86	      acc[selector.key] = selector.value;
 87	      return acc;
 88	    }, {});
 89	
 90	    const newPolicy = produce(policy, (draftPolicy) => {
 91	      selectorLabels.length === 0
 92	        ? delete draftPolicy.spec.nodeSelector
 93	        : (draftPolicy.spec.nodeSelector = nodeSelector);
 94	    });
 95	
 96	    return onSubmit(newPolicy);
 97	  };
 98	
 99	  const nodeAlreadyCovered = qualifiedNodes.find((node) =>
100	    enactments.find(
101	      (enactment) => enactment?.metadata?.labels?.[ENACTMENT_LABEL_NODE] === node.metadata.name,
102	    ),
103	  );
104	
105	  return (
106	    <Modal
107	      onClose={onClose}
108	      isOpen={isOpen}
109	      variant={ModalVariant.small}
110	      className="ocs-modal"
111	    >
112	      <ModalHeader title={t('Node Selector')} />
113	      <ModalBody>
114	        <Form>
115	          <LabelsList model={nodes?.length !== 0 && NodeModel} onLabelAdd={onSelectorLabelAdd}>
116	            {selectorLabels.length > 0 && (
117	              <>
118	                {selectorLabels.map((label) => (
119	                  <LabelRow
120	                    key={label.id}
121	                    label={label}
122	                    onChange={onLabelChange}
123	                    onDelete={onLabelDelete}
124	                  />
125	                ))}
126	              </>
127	            )}
128	          </LabelsList>
129	          {nodes.length !== 0 && (
130	            <NodeCheckerAlert
131	              qualifiedNodes={selectorLabels?.length === 0 ? nodes : qualifiedNodes}
132	              nodesLoaded={nodesLoaded && enactmentsLoaded}
133	            />
134	          )}
135	
136	          {nodeAlreadyCovered && (
137	            <Alert
138	              variant={AlertVariant.warning}
139	              isInline
140	              title={t('This node already has a policy matching it')}
141	            >
142	              {t('Remove all dependencies between the new and existing polices')}
143	            </Alert>
144	          )}
145	
146	          <ActionGroup className="pf-v6-c-form">
147	            <Button type={ButtonType.submit} variant={ButtonVariant.primary} onClick={onSave}>
148	              {t('Save')}
149	            </Button>
150	            <Button type={ButtonType.button} variant={ButtonVariant.secondary} onClick={onClose}>
151	              {t('Cancel')}
152	            </Button>
153	          </ActionGroup>
154	        </Form>
155	      </ModalBody>
156	    </Modal>
157	  );
158	};
159	
160	export default NodeSelectorModal;

